def qwen_template(
    prompt: str, response: Optional[str] = None, add_generation_prompt: bool = False
) -> List[int]:
    messages = [
        {"role": "system", "content": "Pick one of the given options."},
        {"role": "user", "content": prompt},
    ]
    if response is not None:
        messages.append({"role": "assistant", "content": response})

    return tokenizer.apply_chat_template(
        messages,
        tokenize=True,
        add_generation_prompt=add_generation_prompt
        if response is None
        else False,  # чтобы начинать генерацию с ответа ассистента

