DATA_PATH = "https://raw.githubusercontent.com/nrimsky/CAA/refs/heads/main/datasets/generate/refusal/generate_dataset.json"


class ComparisonDataset(Dataset):
    def __init__(self, data_path):
        self.data = requests.get(data_path).json()

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx) -> Tuple[torch.Tensor, torch.Tensor]:
        item = self.data[idx]
        q_text = item["question"]

        pos_answer = item["answer_matching_behavior"]
        neg_answer = item["answer_not_matching_behavior"]

        p_tokens = torch.tensor(
            qwen_template(prompt=q_text, response=pos_answer),
            dtype=torch.int64
        )
        n_tokens = torch.tensor(
            qwen_template(prompt=q_text, response=neg_answer),
            dtype=torch.int64
        )

        return p_tokens, n_tokens

